            <kbd className={`px-1.5 py-0.5 rounded text-[10px] font-bold border transition-colors ${isDark ? 'bg-gray-800 border-gray-700 text-gray-500' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>K</kbd>
