          : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-600'
        }`}>
          <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${isOffline ? 'bg-orange-500' : 'bg-emerald-500'}`} />
          {isOffline ? 'Offline' : 'Synced'}
