                  </button>
                </motion.div>
              ))
            )}
          </div>
        </div>
      )}

      {/* FULL-SCREEN LIVE SESSION WORKSPACE */}
      <AnimatePresence>
        {activeQuestion && (
          // @ts-ignore
          <motion.div 
