  Save,
  Trash2,
  Download,
  RefreshCcw,
  AlertTriangle,
  Loader2,
  Camera,
  FileJson,
  Zap,
  LogOut,
  ChevronRight,
  ShieldCheck,
  Globe,
  AlertCircle,
  CheckCircle2
} from 'lucide-react';
import { useTracker } from '../context/TrackerContext';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const Settings: React.FC = () => {
  const { user, updateUserProfile, theme, toggleTheme, syncLeetCode, exportData, logout, changePassword } = useTracker();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Profile');
  const [isSaving, setIsSaving] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  // Local form states
  const [name, setName] = useState(user?.name || '');
  const [email, setEmail] = useState(user?.email || '');
  const [lcUsername, setLcUsername] = useState(user?.leetcodeUsername || '');
  const [ghUsername, setGhUsername] = useState(user?.githubUsername || '');
  const [avatarPreview, setAvatarPreview] = useState<string | null>(user?.avatar || null);

  // Password states
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);

  // Notification states (simulated)
  const [notifDaily, setNotifDaily] = useState(true);
  const [notifWeekly, setNotifWeekly] = useState(false);
  const [notifReview, setNotifReview] = useState(true);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (user) {
      setName(user.name);
      setEmail(user.email);
      setLcUsername(user.leetcodeUsername || '');
      setGhUsername(user.githubUsername || '');
      setAvatarPreview(user.avatar || null);
    }
  }, [user]);

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatarPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerFeedback = () => {
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const handleSaveProfile = async () => {
    setIsSaving(true);
    try {
      await updateUserProfile({
        name,
        email,
        leetcodeUsername: lcUsername,
        githubUsername: ghUsername,
        avatar: avatarPreview || ''
      });
      triggerFeedback();
    } catch (err) {
      alert("Failed to update profile.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentPassword) return alert("Current password is required.");
    if (!newPassword || newPassword.length < 6) return alert("New password must be at least 6 characters.");

    setIsUpdatingPassword(true);
    try {
      await changePassword(currentPassword, newPassword);
      triggerFeedback();
      setCurrentPassword('');
      setNewPassword('');
    } catch (err: any) {
      alert(err.message || "Failed to update password.");
    } finally {
      setIsUpdatingPassword(false);
    }
  };

  const handleSync = async () => {
    if (!lcUsername) return alert("Please enter your LeetCode username.");
    setIsSyncing(true);
    try {
